import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { ArrowLeft, ArrowRight } from 'lucide-react';

function TestimonialCarousel() {
  const [currentIndex, setCurrentIndex] = useState(0);
  const testimonials = [
    {
      quote: 'TechForge has been a game-changer for our business. Their innovative solutions have helped us to increase our sales by 25%.',
      author: 'John Doe, CEO of XYZ Corporation',
    },
    {
      quote: 'We were blown away by the quality of service provided by TechForge. Their team is highly skilled and dedicated.',
      author: 'Jane Smith, Marketing Manager of ABC Company',
    },
    {
      quote: 'TechForge has helped us to streamline our operations and reduce costs. We are extremely satisfied with their services.',
      author: 'Bob Johnson, Operations Manager of DEF Inc.',
    },
  ];

  useEffect(() => {
    const intervalId = setInterval(() => {
      setCurrentIndex((currentIndex + 1) % testimonials.length);
    }, 5000);
    return () => clearInterval(intervalId);
  }, [currentIndex, testimonials.length]);

  return (
    <section className="py-4 md:py-6 lg:py-8 bg-zinc-100">
      <div className="container mx-auto p-4 md:p-6 lg:p-8">
        <h2 className="text-2xl md:text-3xl lg:text-4xl font-bold text-zinc-900 mb-4 md:mb-6 lg:mb-8">
          What Our Clients Say
        </h2>
        <div className="flex justify-center items-center mb-4 md:mb-6 lg:mb-8">
          <motion.button
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.9 }}
            className="bg-zinc-100 text-zinc-900 py-2 px-4 md:py-3 md:px-6 lg:py-4 lg:px-8 rounded-md shadow-md mr-2"
            onClick={() => setCurrentIndex((currentIndex - 1 + testimonials.length) % testimonials.length)}
          >
            <ArrowLeft size={16} />
          </motion.button>
          <motion.div
            initial={{ x: 100, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            transition={{ duration: 0.5 }}
            className="bg-zinc-100 p-4 md:p-6 lg:p-8 rounded-md shadow-md w-full md:w-1/2 lg:w-1/3"
          >
            <p className="text-lg md:text-xl lg:text-2xl text-zinc-600 mb-2 md:mb-4 lg:mb-6">
              {testimonials[currentIndex].quote}
            </p>
            <p className="text-lg md:text-xl lg:text-2xl text-zinc-600">
              {testimonials[currentIndex].author}
            </p>
          </motion.div>
          <motion.button
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.9 }}
            className="bg-zinc-100 text-zinc-900 py-2 px-4 md:py-3 md:px-6 lg:py-4 lg:px-8 rounded-md shadow-md ml-2"
            onClick={() => setCurrentIndex((currentIndex + 1) % testimonials.length)}
          >
            <ArrowRight size={16} />
          </motion.button>
        </div>
      </div>
    </section>
  );
}

export default TestimonialCarousel;

